class Solution:
    def triangleNumber(self, nums):
        n = len(nums)
        count = 0
        for i in range(n):
            for j in range(i + 1, n):
                for k in range(j + 1, n):
                    a, b, c = nums[i], nums[j], nums[k]
                    if a + b > c and a + c > b and b + c > a:
                        count += 1
        return count

