var triangleNumber = function(nums) {
    nums = nums.slice().sort((a, b) => a - b);
    const n = nums.length;
    let count = 0;
    for (let k = n - 1; k >= 2; k--) {
        let l = 0, r = k - 1;
        while (l < r) {
            if (nums[l] + nums[r] > nums[k]) {
                count += r - l;
                r--;
            } else {
                l++;
            }
        }
    }
    return count;
};
